/* ============================================================
   SOUNDS.JS — Все звуки игры Василий-прыгун
   MP3 файлы встроены как base64, Web Audio API для синтетических
   ============================================================ */

const Sounds = (() => {
  let actx = null;
  let sfxVol   = parseFloat(localStorage.getItem('vj_sfx_vol')   ?? '0.6');
  let musicVol = parseFloat(localStorage.getItem('vj_music_vol') ?? '0.4');
  let sfxOn    = (localStorage.getItem('vj_sfx_on')   ?? '1') === '1';
  let musicOn  = (localStorage.getItem('vj_music_on') ?? '1') === '1';

  let jetSource  = null; // зацикленный джетпак
  let shieldHum  = null; // тихое гудение щита (синтетическое)

  function getCtx() {
    if (!actx) actx = new (window.AudioContext || window.webkitAudioContext)();
    if (actx.state === 'suspended') actx.resume();
    return actx;
  }

  /* --- Кэш декодированных аудиобуферов --- */
  const _bufCache = {};
  const _b64 = {
    woodBreak: 'data:audio/mpeg;base64,',
    sparkleCollect: 'data:audio/mpeg;base64,',
    shieldPickup: 'data:audio/mpeg;base64,',
    shieldBreak: 'data:audio/mpeg;base64,',
    jetLoop: 'data:audio/mpeg;base64,',
    spring: 'data:audio/mpeg;base64,',
    promo: 'data:audio/mpeg;base64,',
    zwuk: 'data:audio/mpeg;base64,',
    zwuk: 'data:audio/mpeg;base64,',
  };

  async function getBuffer(key) {
    if (_bufCache[key]) return _bufCache[key];
    const ac  = getCtx();
    const res = await fetch(_b64[key]);
    const arr = await res.arrayBuffer();
    const buf = await ac.decodeAudioData(arr);
    _bufCache[key] = buf;
    return buf;
  }

  async function playBuf(key, vol = 1, loop = false) {
    if (!sfxOn && !loop) return null;
    if (loop && !musicOn) return null;
    try {
      const ac  = getCtx();
      const buf = await getBuffer(key);
      const src = ac.createBufferSource();
      const gain = ac.createGain();
      src.buffer = buf;
      src.loop   = loop;
      src.connect(gain);
      gain.connect(ac.destination);
      gain.gain.setValueAtTime((loop ? musicVol : sfxVol) * vol, ac.currentTime);
      src.start();
      return { src, gain };
    } catch(e) { console.warn('playBuf', key, e); return null; }
  }

  /* --- синтетические звуки --- */
  function tone(freq, dur, vol, shape = 'square') {
    if (!sfxOn) return;
    try {
      const ac = getCtx();
      const osc  = ac.createOscillator();
      const gain = ac.createGain();
      osc.connect(gain); gain.connect(ac.destination);
      osc.type = shape;
      osc.frequency.setValueAtTime(freq, ac.currentTime);
      gain.gain.setValueAtTime(vol * sfxVol, ac.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.0001, ac.currentTime + dur);
      osc.start(ac.currentTime);
      osc.stop(ac.currentTime + dur);
    } catch(e) {}
  }

  function seq(notes, vol, shape = 'square') {
    if (!sfxOn) return;
    try {
      const ac = getCtx();
      let t = ac.currentTime;
      for (const [freq, dur] of notes) {
        const osc  = ac.createOscillator();
        const gain = ac.createGain();
        osc.connect(gain); gain.connect(ac.destination);
        osc.type = shape;
        osc.frequency.setValueAtTime(freq, t);
        gain.gain.setValueAtTime(vol * sfxVol, t);
        gain.gain.exponentialRampToValueAtTime(0.0001, t + dur);
        osc.start(t); osc.stop(t + dur);
        t += dur;
      }
    } catch(e) {}
  }

  function stopNode(node) {
    if (!node) return;
    try {
      node.gain.gain.setValueAtTime(node.gain.gain.value, getCtx().currentTime);
      node.gain.gain.exponentialRampToValueAtTime(0.0001, getCtx().currentTime + 0.2);
      setTimeout(() => { try { node.src.stop(); } catch(e){} }, 250);
    } catch(e) {}
  }

  /* Предзагрузка всех буферов после первого клика */
  function preload() {
    Object.keys(_b64).forEach(key => getBuffer(key).catch(() => {}));
  }

  return {
    preload,

    setSfxVol(v)   { sfxVol   = v; localStorage.setItem('vj_sfx_vol', v);
      if (shieldHum) shieldHum.gain.gain.setValueAtTime(v * 0.06, getCtx().currentTime); },
    setMusicVol(v) { musicVol = v; localStorage.setItem('vj_music_vol', v);
      if (jetSource) jetSource.gain.gain.setValueAtTime(v * 0.5, getCtx().currentTime); },
    setSfxOn(on)   { sfxOn   = on; localStorage.setItem('vj_sfx_on',   on ? '1' : '0'); },
    setMusicOn(on) { musicOn = on; localStorage.setItem('vj_music_on', on ? '1' : '0');
      if (!on) { this.jetStop(); this.shieldStop(); } },
    getSfxVol()    { return sfxVol; },
    getMusicVol()  { return musicVol; },
    isSfxOn()      { return sfxOn; },
    isMusicOn()    { return musicOn; },

    /* Прыжок с обычной платформы */
    zwuk()  { playBuf('zwuk', sfxVol); },
    jump() { tone(120, 0.06, 0.22, 'sine'); tone(200, 0.08, 0.14, 'triangle'); },

    /* Прыжок с деревяшки */
    jumpWood() {
      try {
        const ac  = getCtx();
        const buf = ac.createBuffer(1, ac.sampleRate * 0.06, ac.sampleRate);
        const d   = buf.getChannelData(0);
        for (let i = 0; i < d.length; i++) d[i] = (Math.random()*2-1) * Math.exp(-i/800);
        const src  = ac.createBufferSource(); src.buffer = buf;
        const gain = ac.createGain();
        gain.gain.setValueAtTime(0.3 * sfxVol, ac.currentTime);
        src.connect(gain); gain.connect(ac.destination); src.start();
        tone(90, 0.07, 0.15, 'triangle');
      } catch(e) {}
    },

    /* Разлом бревна — MP3 */
    woodBreak() { playBuf('woodBreak', 0.8); },

    /* Пружина — MP3 */
    spring() { playBuf('spring', 0.28); },
    sparkleCollect() { playBuf('sparkleCollect', 0.5); },

    /* Подбор щита — MP3 (радио-звук) */
    shieldPickup() { playBuf('shieldPickup', 0.7); },

    /* Тихое гудение щита пока активен */
    shieldStart() {
      this.shieldStop();
      if (!sfxOn) return;
      try {
        const ac   = getCtx();
        const osc  = ac.createOscillator();
        const gain = ac.createGain();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(220, ac.currentTime);
        gain.gain.setValueAtTime(0.06 * sfxVol, ac.currentTime);
        osc.connect(gain); gain.connect(ac.destination); osc.start();
        shieldHum = { src: osc, gain };
      } catch(e) {}
    },
    shieldStop() {
      if (shieldHum) { stopNode(shieldHum); shieldHum = null; }
    },

    /* Звук разбитого щита */
    shieldBreak() { playBuf('shieldBreak', 0.8); },

    /* Подбор джетпака */
    jetPickup() { seq([[200,0.04],[400,0.04],[800,0.06]], 0.18, 'sawtooth'); },

    /* Зацикленный рёв двигателя */
    async jetStart() {
      this.jetStop();
      const node = await playBuf('jetLoop', 0.5, true);
      jetSource = node;
    },
    jetStop() {
      if (jetSource) { stopNode(jetSource); jetSource = null; }
    },

    /* Блёстка */
    gem() { seq([[1200,0.04],[1600,0.06]], 0.12, 'sine'); },

    /* Кнопка */
    click() { tone(480, 0.05, 0.1, 'sine'); },

    /* Смерть */
    die() {
      this.jetStop(); this.shieldStop();
      seq([[330,0.08],[220,0.08],[110,0.18]], 0.18, 'square');
    },

    /* Промокод — MP3 */
    promo() { playBuf('promo', 0.8); },

    /* ============================================================
       ФОНОВЫЕ ЗВУКИ ПРИРОДЫ — реальная запись болота (сверчки, лягушки, жабы)
       Зациклена, играет тихо на фоне
       ============================================================ */
    _ambientAudio: null,
    startAmbient() {
      if (this._ambientAudio) return;
      try {
        const a = new Audio('sounds/swamp-ambient.mp3');
        a.loop = true;
        a.volume = musicVol * 0.35; // тихий фон, не перекрывает игровые звуки
        a.play().catch(() => {});
        this._ambientAudio = a;
      } catch(e) {}
    },
    stopAmbient() {
      if (this._ambientAudio) {
        try { this._ambientAudio.pause(); } catch(e) {}
        this._ambientAudio = null;
      }
    },
    setAmbientVolume(v) {
      if (this._ambientAudio) this._ambientAudio.volume = v * 0.35;
    },
  };
})();
